1	import { Injectable } from '@angular/core';
2	import {
3	  HttpInterceptor,
4	  HttpRequest,
5	  HttpHandler,
6	  HttpEvent
7	} from '@angular/common/http';
8	import { Observable } from 'rxjs';
9	import { finalize } from 'rxjs/operators';
10	import { LoaderService } from '../services/loader.service';
11	
12	/**
13	 * Loader interceptor - DISABLED by default.
14	 * 
15	 * The loader will only show for requests with header 'X-Enable-Loader: true'.
16	 * Services should add this header when they want to show the loader.
17	 * 
18	 * Example in service:
19	 * { headers: new HttpHeaders().set('X-Enable-Loader', 'true') }
20	 */
21	@Injectable({
22	  providedIn: 'root'
23	})
24	export class LoaderInterceptor implements HttpInterceptor {
25	  private readonly enableHeader = 'X-Enable-Loader';
26	
27	  constructor(private readonly loaderService: LoaderService) {}
28	
29	  intercept(request: HttpRequest<unknown>, next: HttpHandler): Observable<HttpEvent<unknown>> {
30	    let shouldEnable = false;
31	    try {
32	      shouldEnable = !!(request?.headers?.has?.(this.enableHeader));
33	    } catch {
34	      shouldEnable = false;
35	    }
36	
37	    const cleanedRequest = shouldEnable && request?.headers
38	      ? request.clone({ headers: request.headers.delete(this.enableHeader) })
39	      : request;
40	
41	    if (shouldEnable) {
42	      this.loaderService.increment();
43	    }
44	
45	    return next.handle(cleanedRequest).pipe(
46	      finalize(() => {
47	        if (shouldEnable) {
48	          this.loaderService.decrement();
49	        }
50	      })
51	    );
52	  }
53	}
