4	@Injectable({
5	  providedIn: 'root'
6	})
7	export class LoaderService {
8	  private pendingRequests = 0;
9	  private readonly isLoadingSubject = new BehaviorSubject<boolean>(false);
10	
11	  /**
12	   * Emits true while there is at least one in-flight request that did not opt out.
13	   */
14	  readonly isLoading$: Observable<boolean> = this.isLoadingSubject.asObservable();
15	
16	  show(): void {
17	    this.increment();
18	  }
19	
20	  hide(): void {
21	    this.decrement();
22	  }
23	
24	  increment(): void {
25	    this.pendingRequests += 1;
26	    if (!this.isLoadingSubject.value) {
27	      this.isLoadingSubject.next(true);
28	    }
29	  }
30	
31	  decrement(): void {
32	    this.pendingRequests = Math.max(this.pendingRequests - 1, 0);
33	    if (this.pendingRequests === 0 && this.isLoadingSubject.value) {
34	      this.isLoadingSubject.next(false);
35	    }
36	  }
37	
38	  reset(): void {
39	    this.pendingRequests = 0;
40	    this.isLoadingSubject.next(false);
41	  }
42	}
