2	 * Excel-style input evaluator.
3	 * - Plain number  →  parseFloat (e.g. "7.5"  → 7.5)
4	 * - Starts with = →  evaluate the expression (e.g. "=5+2.5" → 7.5)
5	 * Throws if the expression after = is invalid.
6	 */
7	export function evaluateInput(raw: string): number {
8	  const s = (raw ?? '').trim();
9	  if (s.startsWith('=')) {
10	    return evaluateMathExpr(s.slice(1));
11	  }
12	  const n = parseFloat(s);
13	  if (isNaN(n)) throw new Error('Not a number');
14	  return n;
15	}
