17	/**
18	 * Safe arithmetic expression evaluator.
19	 * Supports: numbers, decimals, +  -  *  /  ( )  unary minus
20	 * Rejects anything outside that character set — no eval(), no Function().
21	 */
22	export function evaluateMathExpr(raw: string): number {
23	  const expr = raw.trim();
24	
25	  if (expr === '' || expr === null) {
26	    throw new Error('Expression is empty');
27	  }
28	
29	  // Whitelist: digits, decimal point, operators, parentheses, whitespace only
30	  if (!/^[\d\s+\-*/.()]+$/.test(expr)) {
