65	    let left = parseFactor();
66	    skip();
67	    while (pos < expr.length && (expr[pos] === '*' || expr[pos] === '/')) {
68	      const op = expr[pos++];
69	      const right = parseFactor();
70	      left = op === '*' ? left * right : left / right;
71	      skip();
72	    }
73	    return left;
74	  }
75	
76	  function parseAddSub(): number {
77	    let left = parseMulDiv();
78	    skip();
79	    while (pos < expr.length && (expr[pos] === '+' || expr[pos] === '-')) {
80	      const op = expr[pos++];
81	      const right = parseMulDiv();
82	      left = op === '+' ? left + right : left - right;
83	      skip();
84	    }
85	    return left;
86	  }
